import{_ as d,H as o,f as e,i as r}from"./chunks/framework.DLd0CbzH.js";const b=JSON.parse('{"title":"网络代理","description":"","frontmatter":{},"headers":[],"relativePath":"api/proxy.md","filePath":"api/proxy.md","lastUpdated":1780150416000}'),a={name:"api/proxy.md"};function c(i,t,s,h,n,u){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="网络代理" tabindex="-1">网络代理 <a class="header-anchor" href="#网络代理" aria-label="Permalink to &quot;网络代理&quot;">​</a></h1><p>提供访问外部网站的代理服务，分为 GitHub 专用代理和通用代理。</p><hr><h2 id="一、github-专用加速模式-无需授权" tabindex="-1">一、GitHub 专用加速模式（无需授权） <a class="header-anchor" href="#一、github-专用加速模式-无需授权" aria-label="Permalink to &quot;一、GitHub 专用加速模式（无需授权）&quot;">​</a></h2><p>该模式专为 GitHub 及其关联域名设计，<strong>无需任何密钥</strong>，直接通过特定路径前缀即可代理请求。</p><h3 id="可用前缀" tabindex="-1">可用前缀 <a class="header-anchor" href="#可用前缀" aria-label="Permalink to &quot;可用前缀&quot;">​</a></h3><table tabindex="0"><thead><tr><th>前缀</th><th>功能</th></tr></thead><tbody><tr><td><code>/gh/</code></td><td>普通代理，直接返回原始内容（不重写页面）</td></tr><tr><td><code>/gh_fix/</code></td><td>智能代理，自动重写 HTML 中的链接、资源路径，解决样式丢失问题</td></tr></tbody></table><h3 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h3><ol><li><p>方法一： 将你要访问的 GitHub 原始 URL 前面添加 （下载文件时推荐）： <a href="https://api.undz.cn/gh/" target="_blank" rel="noreferrer">https://api.undz.cn/gh/</a> 或者 （访问GitHub网页时推荐） <a href="https://api.undz.cn/gh_fix/" target="_blank" rel="noreferrer">https://api.undz.cn/gh_fix/</a></p></li><li><p>方法二： 将你要访问的 GitHub 原始 URL 转换为以下格式： <a href="https://api.undz.cn/gh/%5B%E7%B1%BB%E5%9E%8B%5D/%5B%E5%89%A9%E4%BD%99%E8%B7%AF%E5%BE%84%5D" target="_blank" rel="noreferrer">https://api.undz.cn/gh/[类型]/[剩余路径]</a> 其中 <code>[类型]</code> 支持以下简写（自动映射到真实的 GitHub 域名）：</p></li></ol><table tabindex="0"><thead><tr><th>简写</th><th>对应域名</th><th>说明</th></tr></thead><tbody><tr><td><code>www</code></td><td>github.com</td><td>GitHub 主站</td></tr><tr><td><code>raw</code></td><td>raw.githubusercontent.com</td><td>原始文件下载</td></tr><tr><td><code>gist</code></td><td>gist.github.com</td><td>Gist 代码片段</td></tr><tr><td><code>api</code></td><td>api.github.com</td><td>GitHub API</td></tr><tr><td><code>io</code></td><td>github.io</td><td>GitHub Pages</td></tr><tr><td><code>camo</code></td><td>camo.githubusercontent.com</td><td>图片缓存</td></tr><tr><td><code>avatars</code></td><td>avatars.githubusercontent.com</td><td>用户头像</td></tr><tr><td><code>usercontent</code></td><td>user-content.githubusercontent.com</td><td>用户生成内容</td></tr><tr><td><code>assets</code></td><td>assets-cdn.github.com</td><td>资源 CDN</td></tr><tr><td><code>ghs</code></td><td>github.global.ssl.fastly.net</td><td>GitHub 全球加速节点</td></tr><tr><td><code>greasyfork</code></td><td>greasyfork.org</td><td>GreasyFork 脚本站</td></tr><tr><td><code>upgf</code></td><td>update.greasyfork.org</td><td>GreasyFork 更新源</td></tr><tr><td><code>dev</code></td><td>github.dev</td><td>GitHub Web 编辑器</td></tr><tr><td><code>githubassets</code></td><td>github.githubassets.com</td><td>GitHub 静态资源</td></tr><tr><td><code>support</code></td><td>support-assets.githubassets.com</td><td>GitHub 支持资源</td></tr><tr><td><code>edu</code></td><td>education.github.com</td><td>GitHub 教育</td></tr><tr><td><code>res</code></td><td>resources.github.com</td><td>GitHub 资源</td></tr><tr><td><code>upload</code></td><td>uploads.github.com</td><td>GitHub 上传服务</td></tr><tr><td><code>ap</code></td><td>archiveprogram.github.com</td><td>GitHub 归档计划</td></tr><tr><td><code>guc</code></td><td>githubusercontent.com</td><td>GitHub 用户内容泛域名</td></tr><tr><td><code>cloud</code></td><td>cloud.githubusercontent.com</td><td>云图片缓存</td></tr><tr><td><code>avatars0</code></td><td>avatars0.githubusercontent.com</td><td>头像 0 号节点</td></tr><tr><td><code>avatars1</code></td><td>avatars1.githubusercontent.com</td><td>头像 1 号节点</td></tr><tr><td><code>avatars2</code></td><td>avatars2.githubusercontent.com</td><td>头像 2 号节点</td></tr><tr><td><code>avatars3</code></td><td>avatars3.githubusercontent.com</td><td>头像 3 号节点</td></tr><tr><td><code>avatars4</code></td><td>avatars4.githubusercontent.com</td><td>头像 4 号节点</td></tr><tr><td><code>userimg</code></td><td>user-images.githubusercontent.com</td><td>用户上传图片</td></tr><tr><td><code>objects</code></td><td>objects.githubusercontent.com</td><td>对象存储</td></tr><tr><td><code>pui</code></td><td>private-user-images.githubusercontent.com</td><td>私有用户图片</td></tr><tr><td><code>pages</code></td><td>pages.github.com</td><td>GitHub Pages 信息</td></tr><tr><td><code>app</code></td><td>githubapp.com</td><td>GitHub 应用域名</td></tr></tbody></table><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><ol><li><p><strong>访问 GitHub 仓库首页</strong><br> 原始地址：<code>https://github.com/octocat/Hello-World</code><br> 代理地址：<code>https://api.undz.cn/gh/www/octocat/Hello-World</code></p></li><li><p><strong>下载 raw 文件</strong><br> 原始地址：<code>https://raw.githubusercontent.com/octocat/Hello-World/master/README</code><br> 代理地址：<code>https://api.undz.cn/gh/raw/octocat/Hello-World/master/README</code></p></li><li><p><strong>查看 Gist</strong><br> 原始地址：<code>https://gist.github.com/username/abc123</code><br> 代理地址：<code>https://api.undz.cn/gh/gist/username/abc123</code></p></li><li><p><strong>GitHub API 调用</strong><br> 原始地址：<code>https://api.github.com/users/octocat</code><br> 代理地址：<code>https://api.undz.cn/gh/api/users/octocat</code></p></li></ol><blockquote><p>💡 如果代理后页面出现样式错乱或图片缺失，请尝试使用 <strong><code>/gh_fix/</code></strong> 前缀，它会自动重写页面内的链接，修复相对路径和 CSP 限制。</p></blockquote><hr><h2 id="二、通用代理模式" tabindex="-1">二、通用代理模式 <a class="header-anchor" href="#二、通用代理模式" aria-label="Permalink to &quot;二、通用代理模式&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">此代理不公开</p><p>此代理不面向公众开放</p></div><hr><h2 id="三、工作原理" tabindex="-1">三、工作原理 <a class="header-anchor" href="#三、工作原理" aria-label="Permalink to &quot;三、工作原理&quot;">​</a></h2><p>代理服务基于 Cloudflare Workers 实现：</p><ul><li><strong>请求拦截</strong>：根据路径前缀识别代理请求，提取目标 URL。</li><li><strong>内容获取</strong>：使用自定义 User-Agent 向上游发起请求，跟随重定向。</li><li><strong>智能重写</strong>（<code>*_fix</code> 模式）：对返回的 HTML 进行解析，重写所有 <code>script</code>、<code>link</code>、<code>img</code>、<code>a</code> 等标签的链接，使其再次通过代理，同时移除 <code>integrity</code> 属性以避免 SRI 校验失败，并删除 CSP 头防止浏览器拦截。</li><li><strong>GitHub 专用优化</strong>：内置 30+ 个 GitHub 相关域名的自动转换，支持短路径写法。</li></ul><hr><h2 id="四、注意事项与合理使用提醒" tabindex="-1">四、注意事项与合理使用提醒 <a class="header-anchor" href="#四、注意事项与合理使用提醒" aria-label="Permalink to &quot;四、注意事项与合理使用提醒&quot;">​</a></h2><p>代理服务为公共或半公共服务，请遵守以下准则：</p><ol><li><p><strong>尊重版权与法律</strong><br> 请勿利用代理访问或传播侵权内容、违反中国法律法规或 GitHub 服务条款的材料。</p></li><li><p><strong>禁止滥用</strong><br> 不要使用代理进行大规模爬虫、压力测试、暴力破解、刷流量等行为，以免影响他人正常使用。</p></li><li><p><strong>密钥安全</strong><br> 如需使用通用代理，密钥为个人凭证，请勿上传至公开代码仓库、聊天记录或截图中。密钥泄露可导致他人滥用您的授权。</p></li><li><p><strong>服务可用性</strong><br> 代理服务由个人维护，不保证 100% 可用。如遇到响应缓慢或错误，可稍后重试或尝试切换 <code>/gh_fix/</code> 与 <code>/gh/</code> 模式。</p></li><li><p><strong>隐私说明</strong><br> 代理服务会记录访问的 IP 地址和请求路径，用于排查问题和防止滥用。完整 URL 可能会经过服务端，请勿传递敏感信息（如包含 Token 的私有链接）。</p></li><li><p><strong>GitHub 专用模式无需授权</strong>，但也请合理使用，避免对上游 GitHub 造成过量请求。</p></li></ol><hr><h2 id="五、故障排除" tabindex="-1">五、故障排除 <a class="header-anchor" href="#五、故障排除" aria-label="Permalink to &quot;五、故障排除&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>可能原因</th><th>解决办法</th></tr></thead><tbody><tr><td>返回 403 Forbidden</td><td>访问通用代理但未授权</td><td>先完成 <code>/auth-proxy</code> 授权流程</td></tr><tr><td>返回 400 Bad Request</td><td>代理路径格式错误</td><td>检查是否漏掉协议（<code>http://</code> 或 <code>https://</code>）</td></tr><tr><td>页面样式丢失</td><td>HTML 中的相对路径未被转换</td><td>改用 <code>*_fix</code> 模式（如 <code>/gh_fix/</code> 或 <code>/proxy_fix/</code>）</td></tr><tr><td>授权成功后依然 403</td><td>Cookie 未携带或已过期</td><td>清除浏览器缓存/重试授权，或重新获取密钥</td></tr><tr><td>返回 5xx 错误</td><td>上游服务或代理内部错误</td><td>稍后重试，或联系服务提供者</td></tr></tbody></table><hr><h2 id="六、写在最后" tabindex="-1">六、写在最后 <a class="header-anchor" href="#六、写在最后" aria-label="Permalink to &quot;六、写在最后&quot;">​</a></h2><p>本代理服务旨在为开发者提供一个便捷的 GitHub 访问加速方案，适合在科研、学习、开源贡献等场景下使用。如果你觉得有用，可以分享给需要的朋友，但请一并转发本文的使用规范。</p><p><strong>快乐编码，从流畅访问 GitHub 开始！</strong></p>',31)])])}const g=d(a,[["render",c]]);export{b as __pageData,g as default};
